      expect(Array.isArray(emails)).toBe(true);
      expect(emails.length).toBeLessThanOrEqual(limit);
      emails.forEach((email) => {
        expect(email).toMatchObject({
          id: expect.any(String),
          threadId: expect.any(String),
          subject: expect.any(String),
          from: expect.objectContaining({
            email: expect.any(String),
            raw: expect.any(String),
          }),
          date: expect.any(Date),
          isProcessed: expect.any(Boolean),
        });
        expect(email.date.getTime()).toBeGreaterThanOrEqual(startDate.getTime());
        expect(email.date.getTime()).toBeLessThanOrEqual(endDate.getTime());
      });
    });

    it('should respect limit parameter', async () => {
      const startDate = new Date('2025-01-01');
      const endDate = new Date('2025-12-31');
