/**
 * Unit tests for minimal database email query service (T036h)
 *
 * TDD Approach: Write comprehensive tests FIRST covering:
 * - SQL query generation and execution
 * - Result mapping to EmailMessage interface
 * - Error handling and edge cases
 * - Basic filtering (date range, limit, unclassified)
 */

import { EmailMessage } from '../../../classification-engine/src/types/email-message';
import {
  fetchEmailsByDateRange,
  fetchEmailById,
  fetchUnclassifiedEmails,
  closePool,
} from '../../src/persistence/email-query';

describe('EmailQuery Service', () => {
  afterAll(async () => {
    await closePool();
  });

  describe('fetchEmailsByDateRange', () => {
    it('should fetch emails within specified date range', async () => {
      // Arrange
      const startDate = new Date('2025-09-01');
      const endDate = new Date('2025-09-30');
      const limit = 10;

      // Act
      const emails = await fetchEmailsByDateRange(startDate, endDate, limit);

      // Assert
      expect(Array.isArray(emails)).toBe(true);
      expect(emails.length).toBeLessThanOrEqual(limit);
      emails.forEach((email) => {
        expect(email).toMatchObject({
          id: expect.any(String),
          threadId: expect.any(String),
          subject: expect.any(String),
          from: expect.objectContaining({
            email: expect.any(String),
            raw: expect.any(String),
          }),
          date: expect.any(Date),
          isProcessed: expect.any(Boolean),
        });
        expect(email.date.getTime()).toBeGreaterThanOrEqual(startDate.getTime());
        expect(email.date.getTime()).toBeLessThanOrEqual(endDate.getTime());
      });
    });

    it('should respect limit parameter', async () => {
      const startDate = new Date('2025-01-01');
      const endDate = new Date('2025-12-31');
      const limit = 5;

      const emails = await fetchEmailsByDateRange(startDate, endDate, limit);

      expect(emails.length).toBeLessThanOrEqual(limit);
    });

    it('should return empty array when no emails in date range', async () => {
      const startDate = new Date('2020-01-01');
      const endDate = new Date('2020-01-02');

      const emails = await fetchEmailsByDateRange(startDate, endDate);

      expect(emails).toEqual([]);
    });

    it('should throw error for invalid date range', async () => {
      const startDate = new Date('2025-12-31');
      const endDate = new Date('2025-01-01'); // end before start

      await expect(fetchEmailsByDateRange(startDate, endDate)).rejects.toThrow(
        /Invalid date range|start date must be before end date/i
      );
    });

    it('should use default limit when not specified', async () => {
      const startDate = new Date('2025-01-01');
      const endDate = new Date('2025-12-31');

      const emails = await fetchEmailsByDateRange(startDate, endDate);

      // Should not throw and should have reasonable limit (100)
      expect(emails.length).toBeLessThanOrEqual(100);
    });
  });

  describe('fetchEmailById', () => {
    it('should fetch single email by message ID', async () => {
      // This test requires a known message ID from the database
      // We'll make it conditional on database availability
      // Test with mock ID (will throw if not found)
      const testId = 'test-message-id-12345';

      await expect(fetchEmailById(testId)).rejects.toThrow(/not found|does not exist/i);
    });

    it('should return complete EmailMessage structure', async () => {
      // Skip if no test data available
      // This would work with real data
      // const email = await fetchEmailById('real-id');
      // expect(email).toMatchObject({ id, subject, from, ... });
    });

    it('should throw error for null or empty message ID', async () => {
      await expect(fetchEmailById('')).rejects.toThrow(/message.*id.*required/i);
      await expect(fetchEmailById(null as any)).rejects.toThrow(/message.*id.*required/i);
    });

    it('should handle database connection errors gracefully', async () => {
      // This will be tested with connection pool errors
      // Test will fail initially until implementation handles errors
      await expect(fetchEmailById('test-id')).rejects.toThrow();
    });
  });

  describe('fetchUnclassifiedEmails', () => {
    it('should fetch emails without classification_session records', async () => {
      const limit = 10;

      const emails = await fetchUnclassifiedEmails(limit);

      expect(Array.isArray(emails)).toBe(true);
      expect(emails.length).toBeLessThanOrEqual(limit);

      // All emails should not have processingSessionId
      emails.forEach((email) => {
        expect(email.processingSessionId).toBeUndefined();
        expect(email.isProcessed).toBe(false);
      });
    });

    it('should use default limit of 100 when not specified', async () => {
      const emails = await fetchUnclassifiedEmails();

      expect(emails.length).toBeLessThanOrEqual(100);
    });

    it('should return empty array when all emails are classified', async () => {
      // This may or may not return empty depending on database state
      const emails = await fetchUnclassifiedEmails(1);

      expect(Array.isArray(emails)).toBe(true);
    });
  });

  describe('Result Mapping', () => {
    it('should correctly map database columns to EmailMessage interface', async () => {
      const emails = await fetchEmailsByDateRange(new Date('2025-09-01'), new Date('2025-09-30'), 1);

      if (emails.length > 0) {
        const email = emails[0];

        // Required fields
        expect(email.id).toBeDefined();
        expect(email.threadId).toBeDefined();
        expect(email.subject).toBeDefined();
        expect(email.from).toBeDefined();
        expect(email.from.email).toBeDefined();
        expect(email.date).toBeInstanceOf(Date);
        expect(email.isProcessed).toBeDefined();
        expect(email.processingPriority).toBeDefined();

        // Payload structure
        expect(email.payload).toBeDefined();
        expect(email.payload.mimeType).toBeDefined();
        expect(Array.isArray(email.payload.headers)).toBe(true);

        // Gmail labels
        expect(Array.isArray(email.gmailLabels)).toBe(true);

        // Optional fields should be present but may be undefined
        expect(email).toHaveProperty('bodyPlain');
        expect(email).toHaveProperty('bodyHtml');
        expect(email).toHaveProperty('snippet');
      }
    });

    it('should parse JSON fields correctly', async () => {
      const emails = await fetchEmailsByDateRange(new Date('2025-09-01'), new Date('2025-09-30'), 1);

      if (emails.length > 0) {
        const email = emails[0];

        // payload should be object, not string
        expect(typeof email.payload).toBe('object');

        // gmailLabels should be array, not string
        expect(Array.isArray(email.gmailLabels)).toBe(true);

        // from should be object with email property
        expect(typeof email.from).toBe('object');
        expect(typeof email.from.email).toBe('string');
      }
    });
  });

  describe('Error Handling', () => {
    it('should provide meaningful error messages', async () => {
      await expect(fetchEmailById('')).rejects.toThrow(/message.*id.*required/i);
    });

    it('should handle database connection pool errors', async () => {
      // This will be tested when connection pool is unavailable
      // Implementation should wrap pg errors in meaningful messages
    });

    it('should handle malformed data in database', async () => {
      // Implementation should handle JSON parsing errors gracefully
      // and skip/log problematic records
    });
  });
});

